    string expand(string s) {
        int start = 0, end = 0;
        while (end < s.size() && s[end] != '(') end++;
        if (end == s.size()) return s;
        string nonRepeating = s.substr(start, end - start);
        start = end + 1;
        while (start < s.size() && s[start] != ')') start++;
        string repeating = s.substr(start, s.size() - start - 1);
        while (start < s.size() && s[start] == '(') start++;
        string result = nonRepeating;
        while (true) {
            result += repeating;
            if (result.size() > nonRepeating.size()) break;
        }
        return result;
    }
};```
